//line templates/benchmark.qtpl:212
func formatDuration(d time.Duration) string {
	return fmt.Sprintf("%.2fms", float64(d.Nanoseconds())/1000000)
}

func formatSeconds(d time.Duration) string {
	return fmt.Sprintf("%.2fs", d.Seconds())
}

func formatHashRate(rate float64) string {
	if rate >= 1000000000 {
		return fmt.Sprintf("%.2f GH/s", rate/1000000000)
	}
	if rate >= 1000000 {
		return fmt.Sprintf("%.2f MH/s", rate/1000000)
	}
	if rate >= 1000 {
		return fmt.Sprintf("%.2f KH/s", rate/1000)
	}
	return fmt.Sprintf("%.0f H/s", rate)
}

func formatLargeNumber(n int64) string {
	if n >= 1000000000 {
		return fmt.Sprintf("%.2fB", float64(n)/1000000000)
	}
	if n >= 1000000 {
		return fmt.Sprintf("%.2fM", float64(n)/1000000)
	}
	if n >= 1000 {
		return fmt.Sprintf("%.2fK", float64(n)/1000)
	}
	return fmt.Sprintf("%d", n)
}

func cpuHashesPerSecCSV(cpuResult *benchmark.CPUResult) string {
	if cpuResult == nil {
		return ""
	}
	return fmt.Sprintf("%.0f", cpuResult.HashesPerSec)
}

func cpuTotalHashesCSV(cpuResult *benchmark.CPUResult) string {
	if cpuResult == nil {
		return ""
	}
	return fmt.Sprintf("%d", cpuResult.TotalHashes)
}

func cpuNumCPUCSV(cpuResult *benchmark.CPUResult) string {
	if cpuResult == nil {
		return ""
	}
	return fmt.Sprintf("%d", cpuResult.NumCPU)
}

func cpuAvailableMemoryCSV(cpuResult *benchmark.CPUResult) string {
	if cpuResult == nil {
		return ""
	}
	return fmt.Sprintf("%d", cpuResult.AvailableMemoryMB)
}

func formatMemoryMB(mb int64) string {
	if mb >= 1024 {
		return fmt.Sprintf("%.1f GB", float64(mb)/1024)
	}
	return fmt.Sprintf("%d MB", mb)
}
